INSERT INTO seed_skill VALUES
('site-reliability-engineer-alerting-and-runbooks', 'SRE Alerting and Runbooks', 'DevOps & Platform', 'Designing actionable alerts and runbooks that reduce response time, clarify ownership, and support safe recovery.'),
('site-reliability-engineer-architecture', 'Reliability Architecture', 'Architecture & System Design', 'Evaluating service dependencies, redundancy, failure modes, scalability, and reliability tradeoffs.'),
('site-reliability-engineer-automation', 'Reliability Automation', 'DevOps & Platform', 'Automating operational workflows with safe inputs, logging, rollback behavior, and human review points.'),
('site-reliability-engineer-cybersecurity', 'Operational Security', 'Cybersecurity', 'Applying access boundaries, patching, secure configuration, risk reduction, and incident-aware security practices.'),
('site-reliability-engineer-deployment', 'Safe Deployment', 'DevOps & Platform', 'Designing deployment workflows with validation, progressive rollout, monitoring, and rollback plans.'),
('site-reliability-engineer-governance-risk-and-compliance', 'SRE Governance and Compliance', 'Cybersecurity', 'Collecting operational evidence, defining guardrails, and aligning reliability work with governance requirements.'),
('site-reliability-engineer-grafana', 'Grafana Dashboards', 'DevOps & Platform', 'Building dashboards that expose service health, saturation, errors, latency, and incident context.'),
('site-reliability-engineer-opentelemetry', 'OpenTelemetry Instrumentation', 'DevOps & Platform', 'Using traces, metrics, logs, and context propagation to understand distributed service behavior.'),
('site-reliability-engineer-performance-testing', 'Reliability Performance Testing', 'Software Quality', 'Testing latency, throughput, saturation, and failure behavior to guide scaling and resilience decisions.'),
('site-reliability-engineer-postmortems', 'Blameless Postmortems', 'DevOps & Platform', 'Writing timelines, contributing factors, impact analysis, and follow-up actions without blame.'),
('site-reliability-engineer-prometheus', 'Prometheus Monitoring', 'DevOps & Platform', 'Collecting metrics, writing PromQL queries, and connecting alerts to service health and SLOs.'),
('site-reliability-engineer-resilience-patterns', 'Resilience Patterns', 'Architecture & System Design', 'Applying timeouts, retries, circuit breakers, backpressure, and graceful degradation for reliable services.'),
('site-reliability-engineer-systems-programming', 'Systems Programming for SRE', 'Systems & Operating Systems', 'Understanding processes, memory, signals, I/O, and runtime behavior that affect service reliability.'),
('site-reliability-engineer-technical-writing', 'SRE Technical Writing', 'Career & Communication', 'Writing incident updates, runbooks, postmortems, service docs, and operational handoff notes.'),
('site-reliability-engineer-web', 'SRE Web Fundamentals', 'Web', 'Understanding HTTP, DNS, TLS, caching, and web delivery behavior from a reliability perspective.'),
('site-reliability-engineer-security-hardening', 'Security Hardening for Reliability', 'Cybersecurity', 'Reducing production exposure through secure configuration, patching, identity controls, network boundaries, and verification checks.');
